package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader extendedBufferedReader;
    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                return super.read();
            }
        };
    }

    @Test
    void testReadReturnsCharAndUpdatesLastCharWithoutNewline() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        // Mock super.read() to return a character other than '\n'
        doReturn((int) 'a').when(spyReader).read();

        // We need to call the real read() of ExtendedBufferedReader, but above we mocked read() itself,
        // So instead, we mock the super.read() call inside ExtendedBufferedReader by spying on BufferedReader
        // But since ExtendedBufferedReader extends BufferedReader directly, we can create a subclass for testing
        // or use a different approach:
        // Instead, we create a subclass that overrides super.read() to return desired values.

        // So we create a subclass for testing:
        ExtendedBufferedReader testReader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                return super.read();
            }

            @Override
            public int read() throws IOException {
                // call super.read() from BufferedReader
                return super.read();
            }
        };

        ExtendedBufferedReader testSpy = spy(testReader);

        // Actually, to mock super.read() call inside ExtendedBufferedReader.read(), we must mock BufferedReader's read()
        // So we create a BufferedReader mock that returns desired values:
        BufferedReader brMock = mock(BufferedReader.class);
        when(brMock.read()).thenReturn((int) 'a');
        // But ExtendedBufferedReader extends BufferedReader, so we cannot inject brMock directly.
        // Instead, we create a subclass that overrides super.read() to call brMock.read()
        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                int current = brMock.read();
                if (current == '\n') {
                    lineCounter++;
                }
                lastChar = current;
                return lastChar;
            }
        };

        // Test method
        int result = reader.read();
        assertEquals('a', result);
        // lineCounter should not be incremented
        int lineNumber = invokeGetLineNumber(reader);
        assertEquals(0, lineNumber);
        int lastCharValue = invokeGetLastChar(reader);
        assertEquals('a', lastCharValue);
    }

    @Test
    void testReadReturnsNewlineCharAndIncrementsLineCounter() throws IOException {
        BufferedReader brMock = mock(BufferedReader.class);
        when(brMock.read()).thenReturn((int) '\n');
        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                int current = brMock.read();
                if (current == '\n') {
                    lineCounter++;
                }
                lastChar = current;
                return lastChar;
            }
        };

        int result = reader.read();
        assertEquals('\n', result);
        int lineNumber = invokeGetLineNumber(reader);
        assertEquals(1, lineNumber);
        int lastCharValue = invokeGetLastChar(reader);
        assertEquals('\n', lastCharValue);
    }

    @Test
    void testReadReturnsEndOfStream() throws IOException {
        BufferedReader brMock = mock(BufferedReader.class);
        when(brMock.read()).thenReturn(ExtendedBufferedReader.END_OF_STREAM);
        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                int current = brMock.read();
                if (current == '\n') {
                    lineCounter++;
                }
                lastChar = current;
                return lastChar;
            }
        };

        int result = reader.read();
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        int lineNumber = invokeGetLineNumber(reader);
        assertEquals(0, lineNumber);
        int lastCharValue = invokeGetLastChar(reader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastCharValue);
    }

    private int invokeGetLineNumber(ExtendedBufferedReader reader) {
        try {
            var method = ExtendedBufferedReader.class.getDeclaredMethod("getLineNumber");
            method.setAccessible(true);
            return (int) method.invoke(reader);
        } catch (Exception e) {
            fail("Failed to invoke getLineNumber via reflection: " + e.getMessage());
            return -1;
        }
    }

    private int invokeGetLastChar(ExtendedBufferedReader reader) {
        try {
            var field = ExtendedBufferedReader.class.getDeclaredField("lastChar");
            field.setAccessible(true);
            return (int) field.get(reader);
        } catch (Exception e) {
            fail("Failed to access lastChar via reflection: " + e.getMessage());
            return -1;
        }
    }
}
